// Obtener la respuesta del agente
const rawText = $input.first().json.agentOutput || $input.first().json.output || '';
const extraer = $("Extraer Datos Email").first().json;

// Helper para escapar SQL
const esc = (s) => (s || '').replace(/'/g, "''");

// Buscar acción estructurada
const actionMatch = rawText.match(/###EMAIL_ACTION###\n([\s\S]*?)\n###FIN###/);
let accion = null;
let textoLimpio = rawText;
let clasificacion = 'GENERAL';
let accionTipo = 'redactar_borrador';
let borradorTexto = '';

if (actionMatch) {
  try {
    accion = JSON.parse(actionMatch[1].trim());
    clasificacion = accion.clasificacion || 'GENERAL';
    accionTipo = accion.accion || 'redactar_borrador';
    borradorTexto = accion.borrador || '';
    textoLimpio = rawText.replace(/###EMAIL_ACTION###[\s\S]*?###FIN###/, '').trim();
  } catch (e) {
    console.error('Error parseando acción:', e);
  }
}

// Construir SQLs
const sqlLog = `INSERT INTO workflow_logs (workflow_id, workflow_name, execution_id, nivel, mensaje) VALUES ('workflow-04', 'Correo Inteligente', '${$execution.id}', '${esc(clasificacion)}', '${esc('Email clasificado como ' + clasificacion + ': ' + (extraer.emailSubject || '').substring(0, 100))}');`;

const sqlAccion = `INSERT INTO workflow_logs (workflow_id, workflow_name, execution_id, nivel, mensaje) VALUES ('workflow-04', 'Correo Inteligente', '${$execution.id}', '${esc(accionTipo)}', '${esc('ACCION: ' + accionTipo + ' | ' + JSON.stringify({clasificacion, accionTipo, motivo: accion?.motivo || ''}))}');`;

return [{
  clasificacion: clasificacion,
  accionTipo: accionTipo,
  borradorRespuesta: borradorTexto,
  textoLimpio: textoLimpio,
  sqlLog: sqlLog,
  sqlAccion: sqlAccion,
  // Preservar datos del email
  emailFrom: extraer.emailFrom,
  emailSubject: extraer.emailSubject,
  emailBody: extraer.emailBody,
  emailId: extraer.emailId
}];
